function graphPositions(){ const defaults=Object.fromEntries(graphNodes.map(n=>[n.id,{x:n.x,y:n.y}])); return {...defaults,...(state.graphPositions||{})}; }
function graph(big=false){ const pos=graphPositions(); const selected=state.selectedGraphNode||'T2TRG'; return `<div class="graph-shell">${big?`<div class="graph-toolbar"><span>Visualizacao estilo Obsidian</span><b>Nos arrastaveis</b><b>Clique para detalhes</b><b>Forca por espessura</b></div>`:''}<div class="adjacency-map-wrap ${big?'obsidian-graph':''}"><svg class="graph ${big?'large':''}" data-graph-map="${big?'large':'mini'}" viewBox="0 0 100 76" role="img" aria-label="Mapa de adjacencia interativo"><defs><pattern id="graph-grid" width="4" height="4" patternUnits="userSpaceOnUse"><circle cx="1" cy="1" r=".12" fill="#94a3b8" opacity=".55"/></pattern><filter id="node-glow" x="-60%" y="-60%" width="220%" height="220%"><feGaussianBlur stdDeviation="1.5" result="blur"/><feMerge><feMergeNode in="blur"/><feMergeNode in="SourceGraphic"/></feMerge></filter></defs><rect class="map-bg" x="2" y="2" width="96" height="72" rx="4"/><rect class="map-grid" x="2" y="2" width="96" height="72" rx="4"/>${graphEdges.map(e=>{const a=pos[e.a],b=pos[e.b],active=selected===e.a||selected===e.b||selected===`${e.a}|${e.b}`||selected===`${e.b}|${e.a}`;return `<g class="graph-edge ${e.cls} ${active?'active':''}" data-edge="${e.a}|${e.b}" data-source="${e.a}" data-target="${e.b}"><line x1="${a.x}" y1="${a.y}" x2="${b.x}" y2="${b.y}"/><text x="${(a.x+b.x)/2}" y="${(a.y+b.y)/2-1.4}">${e.score.toFixed(2)}</text></g>`}).join('')}${graphNodes.map(n=>{const p=pos[n.id],active=selected===n.id;return `<g class="graph-node ${active?'active':''}" data-node="${n.id}" transform="translate(${p.x} ${p.y})" style="--node:${n.color}"><circle class="node-halo" r="${big?6.8:5.8}"/><circle r="${big?3.9:3.4}"/><text class="node-initials" y=".9">${n.id.slice(0,2)}</text><rect class="node-label-bg" x="-8.7" y="5.4" width="17.4" height="4.7" rx="2.2"/><text class="node-label" y="8.7">${n.id}</text></g>`}).join('')}</svg></div></div>`; }
function graphSummary(){ const selected=state.selectedGraphNode||'T2TRG'; const edge=selected.includes('|')?graphEdges.find(e=>`${e.a}|${e.b}`===selected||`${e.b}|${e.a}`===selected):null; if(edge){const rel=adjacency.find(a=>(a.a===edge.a&&a.b===edge.b)||(a.a===edge.b&&a.b===edge.a)); return `<div class="map-summary"><small>Conexao</small><h3>${edge.a} <-> ${edge.b}</h3><p>${rel?.summary||edge.label}</p><div class="summary-metrics"><span><b>${edge.score.toFixed(2)}</b> confianca</span><span>${edge.label}</span></div>${(rel?.signals||[edge.cls]).map(tag).join('')}</div>`;} const node=graphNodes.find(n=>n.id===selected)||graphNodes[0]; const group=groups.find(g=>g.acronym===node.id); const edges=graphEdges.filter(e=>e.a===node.id||e.b===node.id).sort((a,b)=>b.score-a.score); return `<div class="map-summary"><small>${node.kind}</small><h3>${node.id} · ${group?.name||node.name}</h3><p>${group?.description||node.summary}</p><div class="summary-metrics"><span><b>${edges.length}</b> conexoes</span><span><b>${group?.drafts??'--'}</b> drafts</span><span><b>${group?.people??'--'}</b> pessoas</span></div><h4>Conexoes fortes</h4>${edges.slice(0,3).map(e=>`<button class="summary-link" data-select-edge="${e.a}|${e.b}">${e.a===node.id?e.b:e.a}<span>${e.score.toFixed(2)}</span></button>`).join('')}</div>`; }
function graphPoint(svg,event){ const p=svg.createSVGPoint(); p.x=event.clientX; p.y=event.clientY; return p.matrixTransform(svg.getScreenCTM().inverse()); }
function updateGraph(svg){ const pos=graphPositions(); svg.querySelectorAll('[data-edge]').forEach(edge=>{const l=edge.querySelector('line'),t=edge.querySelector('text'),a=pos[edge.dataset.source],b=pos[edge.dataset.target]; if(!a||!b)return; l.setAttribute('x1',a.x);l.setAttribute('y1',a.y);l.setAttribute('x2',b.x);l.setAttribute('y2',b.y);t.setAttribute('x',(a.x+b.x)/2);t.setAttribute('y',(a.y+b.y)/2-1.4);}); }
function bindGraph(){ document.querySelectorAll('[data-select-edge]').forEach(b=>b.onclick=()=>{state.selectedGraphNode=b.dataset.selectEdge;save();render();}); document.querySelectorAll('[data-graph-map]').forEach(svg=>{let drag=null; svg.querySelectorAll('[data-edge]').forEach(e=>e.addEventListener('click',ev=>{ev.stopPropagation();state.selectedGraphNode=e.dataset.edge;save();render();})); svg.querySelectorAll('[data-node]').forEach(n=>{n.addEventListener('click',ev=>{ev.stopPropagation();state.selectedGraphNode=n.dataset.node;save();render();}); n.addEventListener('pointerdown',ev=>{if(svg.dataset.graphMap!=='large')return; ev.preventDefault(); const cur=graphPositions()[n.dataset.node],p=graphPoint(svg,ev); drag={node:n,id:n.dataset.node,dx:p.x-cur.x,dy:p.y-cur.y}; n.classList.add('dragging'); n.setPointerCapture(ev.pointerId);}); n.addEventListener('pointermove',ev=>{if(!drag||drag.node!==n)return; const p=graphPoint(svg,ev); state.graphPositions={...graphPositions()}; state.graphPositions[drag.id]={x:Math.max(8,Math.min(92,p.x-drag.dx)),y:Math.max(10,Math.min(66,p.y-drag.dy))}; const q=state.graphPositions[drag.id]; n.setAttribute('transform',`translate(${q.x} ${q.y})`); updateGraph(svg);}); n.addEventListener('pointerup',ev=>{if(!drag||drag.node!==n)return; n.releasePointerCapture(ev.pointerId); n.classList.remove('dragging'); state.selectedGraphNode=drag.id; drag=null; save(); render();});});}); }

function bind(){ $('#auth')?.addEventListener('submit',e=>{e.preventDefault(); state.user={name:($('#email')?.value||'demo').split('@')[0], role:'Participante'}; save(); go(state.onboardingDone?'inicio':'onboarding');}); $('#logout')?.addEventListener('click',()=>{state.user=null;save();go('login')}); $('#q')?.addEventListener('keydown',e=>{if(e.key==='Enter'){state.query=e.target.value;state.srch.q=null;save();go('busca')}}); $('#route')?.addEventListener('click',()=>{state.query=$('#route-q').value;save();go('descoberta')}); $('#run-search')?.addEventListener('click',()=>{state.query=$('#q')?.value||state.query;state.srch.q=null;save();render()}); $('#analyze')?.addEventListener('click',()=>{state.query=$('#discover').value;save();render();toast('Tema analisado')}); $('#create-watch')?.addEventListener('click',()=>{state.watches.unshift({id:'w'+Date.now(),title:$('#watch-title').value||'Novo acompanhamento',type:'Tema',scope:'IRTF + IETF',groups:['T2TRG','CoRE'],cadence:'Semanal',channel:$('#watch-channel').value,updates:0,status:'Ativo'});save();render();}); $('#draft')?.addEventListener('click',async()=>{const group=$('#draft-group').value; const subject=$('#draft-subject').value; try{const r=await fetch('/api/draft',{method:'POST',headers:{'content-type':'application/json'},body:JSON.stringify({group,subject,query:state.query})}); $('#draft-body').value=(await r.json()).body;}catch{$('#draft-body').value+='\n\nSuggested evidence: T2TRG charter and CoRE draft.'} toast('Rascunho gerado');}); $('#copy')?.addEventListener('click',()=>navigator.clipboard?.writeText($('#draft-body').value).then(()=>toast('Texto copiado'))); document.querySelectorAll('[data-go]').forEach(b=>b.onclick=()=>go(b.dataset.go)); document.querySelectorAll('[data-locale]').forEach(b=>b.onclick=()=>{state.locale=b.dataset.locale;save();render()}); document.querySelectorAll('[data-search-type]').forEach(b=>b.onclick=()=>{state.searchType=b.dataset.searchType;save();render()}); document.querySelectorAll('[data-tower-filter]').forEach(b=>b.onclick=()=>{state.towerFilter=b.dataset.towerFilter;save();render()}); document.querySelectorAll('[data-query]').forEach(b=>b.onclick=()=>{state.query=b.dataset.query;state.srch.q=null;save();render()}); document.querySelectorAll('[data-restart-onboarding]').forEach(b=>b.onclick=()=>{state.onboardingStep=1;state.onboardingDone=false;save();toast('Preferencias recalibradas');go('onboarding')}); document.querySelector('[data-onboard-prev]')?.addEventListener('click',()=>{state.onboardingStep=Math.max(1,state.onboardingStep-1);save();render()}); document.querySelector('[data-onboard-next]')?.addEventListener('click',()=>{if(state.onboardingStep>=5){state.onboardingDone=true;save();go('perfil')}else{state.onboardingStep++;save();render()}}); document.querySelectorAll('[data-watch]').forEach(b=>b.onclick=()=>{const g=groups.find(x=>x.acronym===b.dataset.watch); state.watches.unshift({id:'w'+Date.now(),title:g?g.acronym:'Acompanhar '+b.dataset.watch,type:g?'WG/RG':'Tema',scope:g?.kind||'IRTF + IETF',groups:[b.dataset.watch],cadence:'Semanal',channel:'Painel',updates:0,status:'Ativo'});save();toast('Acompanhamento criado')}); document.querySelectorAll('[data-save]').forEach(b=>b.onclick=()=>{if(!state.saved.includes(b.dataset.save))state.saved.push(b.dataset.save);save();toast('Oportunidade salva')}); document.querySelectorAll('[data-read]').forEach(b=>b.onclick=()=>{state.read[b.dataset.read]=!state.read[b.dataset.read];save();render()}); document.querySelectorAll('[data-feedback]').forEach(b=>b.onclick=()=>{state.feedback.push({rating:b.dataset.feedback,at:new Date().toISOString()});save();toast('Feedback registrado')}); document.querySelectorAll('[data-toast]').forEach(b=>b.onclick=()=>toast(b.dataset.toast)); bindGraph(); bindOnboarding(); }
function bindOnboarding(){
  document.querySelectorAll('[data-experience]').forEach(b=>b.onclick=()=>{state.experienceLevel=b.dataset.experience;save();render();});
  document.querySelectorAll('[data-onboard-rg]').forEach(b=>b.onclick=()=>{const rg=b.dataset.onboardRg; state.selectedRgs=state.selectedRgs.includes(rg)?state.selectedRgs.filter(x=>x!==rg):[...state.selectedRgs,rg]; save(); render();});
  document.querySelectorAll('[data-onboard-topic]').forEach(b=>b.onclick=()=>{const topic=b.dataset.onboardTopic; state.selectedTopics=state.selectedTopics.includes(topic)?state.selectedTopics.filter(x=>x!==topic):[...state.selectedTopics,topic]; save(); render();});
  document.querySelector('[data-add-custom-topic]')?.addEventListener('click',()=>{const v=$('#custom-topic')?.value.trim(); if(!v)return; state.customTopic=v; if(!state.selectedTopics.includes(v)) state.selectedTopics=[...state.selectedTopics,v]; save(); render();});
}
function render(){ if(!state.user && state.route!=='login') state.route='login'; const routes={inicio:home,perfil,onboarding,descoberta,busca,grupos,adjacencia,evidencias,pacotes,rascunhos,acompanhamentos,oportunidades,pessoas}; $('#app').innerHTML=state.route==='login'?login():state.route==='onboarding'?onboarding():shell((routes[state.route]||home)()); translateDom(); bind(); }
addEventListener('hashchange',()=>{state.route=location.hash.replace('#/','')||'inicio';render()});

// Carrega o catalogo real (grupos, evidencias, adjacencias) do Supabase e
// re-renderiza. Login e ficticio; os dados do catalogo sao reais (com fallback).
async function loadCatalog(){ const c=await fetchCatalog(); groups=c.groups; evidence=c.evidence; adjacency=c.adjacency; render(); }

render();
loadCatalog();
